const suffixes = {
  1: "-inci",
  5: "-inci",
  8: "-inci",
  70: "-inci",
  80: "-inci",
  2: "-nci",
  7: "-nci",
  20: "-nci",
  50: "-nci",
  3: "-眉nc眉",
  4: "-眉nc眉",
  100: "-眉nc眉",
  6: "-nc谋",
  9: "-uncu",
  10: "-uncu",
  30: "-uncu",
  60: "-谋nc谋",
  90: "-谋nc谋",
};

const getSuffix = (number) => {
  if (number === 0) {
    // special case for zero
    return number + "-谋nc谋";
  }

  const a = number % 10;
  const b = (number % 100) - a;
  const c = number >= 100 ? 100 : null;

  if (suffixes[a]) {
    return suffixes[a];
  } else if (suffixes[b]) {
    return suffixes[b];
  } else if (c !== null) {
    return suffixes[c];
  }
  return "";
};

const ordinalNumber = (dirtyNumber, _options) => {
  const number = Number(dirtyNumber);
  const suffix = getSuffix(number);

  return number + suffix;
};

